-- =========================================================================
-- Mericka Group — Sector x Service matrix pages
-- Run on the live database. Idempotent / safe to re-run.
-- =========================================================================

create table if not exists sector_services (
  id uuid default uuid_generate_v4() primary key,
  sector_slug text not null,
  service_slug text not null,
  title text not null,
  meta_description text,
  content jsonb,
  hero_image_url text,
  display_order integer default 0,
  published boolean default false,
  created_at timestamptz default now(),
  updated_at timestamptz default now(),
  unique (sector_slug, service_slug)
);

alter table sector_services enable row level security;
drop policy if exists "public read sector_services" on sector_services;
create policy "public read sector_services" on sector_services for select using (published = true);
drop policy if exists "admin all sector_services" on sector_services;
create policy "admin all sector_services" on sector_services for all to authenticated using (true) with check (true);

insert into sector_services
  (sector_slug, service_slug, title, meta_description, content, hero_image_url, display_order, published)
values
  ('aerospace', 'scaffolding-and-access-solutions', 'Aerospace — Scaffolding & Access Solutions', 'Mericka Group LLC offers scaffolding and access solutions designed for Aerospace Manufacturing Facilities. Contact us now to learn more.', '{"type":"doc","content":[{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Scaffolding and Access Solutions for Aerospace Manufacturing"}]},{"type":"paragraph","content":[{"type":"text","text":"At Mericka Group, we specialize in providing scaffolding and access solutions tailored to the unique needs of aerospace manufacturing facilities across Texas, Louisiana, and Alaska. We understand the critical nature of aerospace production processes, delivering safe, efficient, and reliable solutions that help projects stay on track and meet stringent industry standards."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Why Choose Mericka Group for Scaffolding and Access Solutions?"}]},{"type":"paragraph","content":[{"type":"text","text":"1. Tailored Access Solutions for Aerospace Manufacturing Facilities"}]},{"type":"paragraph","content":[{"type":"text","text":"We recognize the precision required in aerospace manufacturing and design our scaffolding and access solutions to meet the complexities of these environments. From high-access work areas to specialized safety measures, our solutions prioritize operational efficiency and worker safety."}]},{"type":"paragraph","content":[{"type":"text","text":"2. Unparalleled Project Management with EMMS"}]},{"type":"paragraph","content":[{"type":"text","text":"Using our proprietary Enterprise Management & Metrics System (EMMS), we plan, track, and improve every work front. This systematic approach ensures that crews meet performance metrics, timelines are adhered to, and reporting is accurate."}]},{"type":"paragraph","content":[{"type":"text","text":"3. Commitment to Safety and Excellence"}]},{"type":"paragraph","content":[{"type":"text","text":"Aerospace manufacturing facilities require a culture of safety second to none. Our award-winning safety standards, combined with a dedication to production quality, are why Mericka Group is a trusted contractor for both prime and subcontracted work."}]},{"type":"paragraph","content":[{"type":"text","text":"4. Deep Collaboration Through \"The Merickan Way\""}]},{"type":"paragraph","content":[{"type":"text","text":"At Mericka Group, our management style revolves around partnerships. We collaborate closely with owners and general contractors to identify value-add opportunities and implement customized plans."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Industries We Serve"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Oil & Gas"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Petrochemical"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Semiconductor Manufacturing"}]}]}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"The Merickan Way"}]},{"type":"paragraph","content":[{"type":"text","text":"1. Collaborate - We will discover together where we can add value, and what financial impact that will have on your bottom line."}]},{"type":"paragraph","content":[{"type":"text","text":"2. Plan - We will then identify a project that will benefit from our value add, and provide a customized proposal and execution plan."}]},{"type":"paragraph","content":[{"type":"text","text":"3. Execute - After that, we will start delivering results right away, and will leverage EMMS to monitor progress and ensure we focus on continuous improvement."}]}]}'::jsonb, '/images/scaffolding.jpg', 1, true),
  ('aerospace', 'turnaround-and-outage-support', 'Aerospace — Turnaround & Outage Support', 'Mericka Group LLC is an industry trusted partner in solving turnaround and outage issues for aerospace companies.', '{"type":"doc","content":[{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Aerospace Turnaround and Outage Support Services at Mericka Group LLC"}]},{"type":"paragraph","content":[{"type":"text","text":"In aerospace manufacturing and MRO environments, operational downtime isn''t just costly—it''s critical. At Mericka Group LLC, we provide expertly planned turnaround and outage support services tailored to the unique needs of aerospace facilities operating under strict regulatory, safety, and performance standards."}]},{"type":"paragraph","content":[{"type":"text","text":"Whether you''re planning scheduled equipment overhauls or managing unplanned disruptions, our teams step in to support every stage—ensuring fast, compliant, and coordinated returns to service with minimal disruption to operations."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Specialized Turnaround Services for Aerospace Manufacturing and MRO"}]},{"type":"paragraph","content":[{"type":"text","text":"Mericka Group LLC supports high-complexity aerospace environments, including aircraft manufacturing plants, engine testing sites, composite fabrication facilities, and maintenance hangars. Our services are ideal for:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Scheduled downtime and system upgrades"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Emergency equipment failure response"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Inspection and compliance-driven infrastructure improvements"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Construction and staging during operational pauses"}]}]}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Full-Cycle Aerospace Outage Solutions"}]},{"type":"paragraph","content":[{"type":"text","text":"Our capabilities include:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Pre-shutdown planning (scoping, permits, logistics)"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Temporary infrastructure installation (scaffolding, shelters, modular cleanrooms)"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Shutdown-phase civil and mechanical support"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Rapid mobilization and on-site coordination"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Post-event cleanup, demobilization, and site restoration"}]}]}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Why Aerospace Facilities Trust Mericka Group LLC"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Fast, scalable mobilization for critical shutdowns"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Deep experience in regulated aerospace and defense environments"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"24/7 availability during mission-critical projects"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Proven success in zero-margin-for-error operations"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Nationwide reach with local expertise"}]}]}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Safety-Led. Performance-Focused. Built for Aerospace Reality."}]},{"type":"paragraph","content":[{"type":"text","text":"Turnarounds in aerospace environments demand more than project management—they require a culture of safety, a commitment to precision, and readiness at every level. At Mericka Group LLC, our teams are trained in confined space entry, cleanroom protocols, aerospace compliance, and rapid emergency response."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"The Merickan Way"}]},{"type":"paragraph","content":[{"type":"text","text":"1. Collaborate - We will discover together where we can add value, and what financial impact that will have on your bottom line."}]},{"type":"paragraph","content":[{"type":"text","text":"2. Plan - We will then identify a project that will benefit from our value add, and provide a customized proposal and execution plan."}]},{"type":"paragraph","content":[{"type":"text","text":"3. Execute - After that, we will start delivering results right away, and will leverage EMMS to monitor progress and ensure we focus on continuous improvement."}]}]}'::jsonb, '/images/product-page-scaffolding-and-turnaround.jpg', 2, true),
  ('aerospace', 'nested-facility-maintenance-programs', 'Aerospace — Nested Facility Maintenance', 'Mericka Group LLC delivers precision-driven nested facility maintenance programs for aerospace manufacturing, maximizing uptime, compliance, and safety.', '{"type":"doc","content":[{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Key Aspects of Nested Facility Maintenance for Aerospace Manufacturing"}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Aerospace Facility Maintenance—Simplified with Mericka Group LLC"}]},{"type":"paragraph","content":[{"type":"text","text":"Mericka Group LLC applies precision, coordination, and data analytics to help aerospace manufacturers optimize every aspect of their facility maintenance operations. Our Nested Facility Maintenance Programs (NFMP) are tailored to high-stakes production environments like aircraft assembly lines, composite fabrication areas, and engine testing facilities. From cleanroom-compliant access systems to specialized coatings, insulation, and hazard abatement, we centralize all soft-craft services under one dependable partner."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Strategic Maintenance Hierarchy Built for Aerospace"}]},{"type":"paragraph","content":[{"type":"text","text":"We develop a structured, hierarchical approach to prioritize maintenance across critical aerospace assets—such as autoclaves, robotic assembly arms, cleanrooms, HVAC systems, and load-bearing structures."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Risk-Based Prioritization: Mission-Critical First"}]},{"type":"paragraph","content":[{"type":"text","text":"Our program uses a risk matrix designed for aerospace applications. Maintenance tasks are prioritized based on:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Safety implications (for operators and production integrity)"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Risk of contamination in controlled environments"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Equipment criticality to production flow and quality assurance"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"FAA and AS9100 regulatory requirements"}]}]}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Integrated Scheduling to Minimize Downtime"}]},{"type":"paragraph","content":[{"type":"text","text":"In aerospace, halting a single process can stall entire production lines. NFMP synchronizes maintenance schedules across nested systems to avoid unnecessary downtime. Labor, equipment, and parts are assigned using a centralized scheduling engine to prevent delays or resource conflicts."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Predictive, Data-Driven Maintenance Decisions"}]},{"type":"paragraph","content":[{"type":"text","text":"Real-time sensors and historical performance data feed into predictive models that anticipate wear, contamination risks, or component fatigue before failure occurs."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Why Nested Maintenance is Ideal for Aerospace Facilities"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Maximize Equipment Uptime and Production Quality: Coordinated scheduling prevents minor defects from spiraling into production-halting failures."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Streamlined Cost and Resource Allocation: Predictive and risk-based scheduling eliminates over-servicing while avoiding emergency repairs."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Safety and Regulatory Compliance at the Core: With strict oversight from FAA, OSHA, and AS9100 standards, NFMP ensures safety-critical assets are maintained to spec."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Built for Change: Scalable and Modular - NFMP''s nested structure makes it easy to onboard new equipment, expand production lines, or reconfigure workflows."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Protect Long-Term Asset Performance: Proactively addressing degradation extends the lifecycle of high-value aerospace assets."}]}]}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"The Merickan Way"}]},{"type":"paragraph","content":[{"type":"text","text":"1. Collaborate - We will discover together where we can add value, and what financial impact that will have on your bottom line."}]},{"type":"paragraph","content":[{"type":"text","text":"2. Plan - We will then identify a project that will benefit from our value add, and provide a customized proposal and execution plan."}]},{"type":"paragraph","content":[{"type":"text","text":"3. Execute - After that, we will start delivering results right away, and will leverage EMMS to monitor progress and ensure we focus on continuous improvement."}]}]}'::jsonb, '/images/Nested-Maintenance-Background-Picture.jpg', 3, true),
  ('aerospace', 'subcontracting-partnerships', 'Aerospace — Subcontracting Partnerships', 'We offer subcontracting partnerships with Aerospace manufacturing companies. How can Mericka Group LLC help you? Learn more here.', '{"type":"doc","content":[{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Subcontracting Partnerships with Aerospace Manufacturers"}]},{"type":"paragraph","content":[{"type":"text","text":"Aerospace subcontracting partnerships involve collaboration between primary contractors and specialized suppliers who provide components, materials, or services essential to aerospace manufacturing and operations. These partnerships often rely on long-term agreements to ensure supply chain stability, facilitate innovation through shared expertise, and manage cost efficiencies by leveraging the supplier''s specialization."}]},{"type":"paragraph","content":[{"type":"text","text":"Subcontracting lets you leverage flexibility and peace of mind. Companies gain access to cutting-edge technology and skills without the overhead of developing them in-house. Risk mitigation also improves through diversified supplier networks and shared responsibilities, while operational scalability is enhanced."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"About Mericka Group LLC"}]},{"type":"paragraph","content":[{"type":"text","text":"Mericka Group excels in delivering precision aerospace subcontracting solutions designed to meet rigorous industry standards and evolving technological demands. Our network of vetted suppliers and in-house experts ensure every component adheres to the highest quality benchmarks. We prioritize transparency and traceability throughout the supply chain."}]},{"type":"paragraph","content":[{"type":"text","text":"Our approach focuses on fostering collaboration rather than simple transactional relationships. Mericka Group partners deeply with clients to understand their unique engineering challenges and production timelines, customizing solutions that reduce lead times and optimize cost structures."}]},{"type":"paragraph","content":[{"type":"text","text":"We integrate advanced data analytics and continuous improvement methodologies, ensuring that our partnerships evolve alongside technological advances and market shifts. Our commitment is to provide reliable, flexible, and compliant subcontracting partnerships that empower you to thrive—without compromise."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"The Merickan Way"}]},{"type":"paragraph","content":[{"type":"text","text":"1. Collaborate - We will discover together where we can add value, and what financial impact that will have on your bottom line."}]},{"type":"paragraph","content":[{"type":"text","text":"2. Plan - We will then identify a project that will benefit from our value add, and provide a customized proposal and execution plan."}]},{"type":"paragraph","content":[{"type":"text","text":"3. Execute - After that, we will start delivering results right away, and will leverage EMMS to monitor progress and ensure we focus on continuous improvement."}]}]}'::jsonb, '/images/scaffold-background-2.jpg', 4, true),
  ('aerospace', 'comprehensive-storage-tank-services', 'Aerospace — Comprehensive Storage Tank Services', 'Mericka Group LLC offers Comprehensive Tank Services for Aerospace Manufacturing Companies. Start working with us today.', '{"type":"doc","content":[{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Comprehensive Tank Services for Aerospace Manufacturing Companies"}]},{"type":"paragraph","content":[{"type":"text","text":"Precision in aerospace operations doesn''t stop at the launch pad—it begins with the infrastructure behind every mission. At Mericka Group LLC, we deliver comprehensive aerospace tank services designed to meet the rigorous safety, performance, and engineering standards of today''s space and aviation systems. From cryogenic storage tanks and pressurized vessels to ground support systems and fueling interfaces, we build, inspect, maintain, and upgrade the tanks that fuel aerospace innovation."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Specialized Tank Services for Aerospace & Launch Operations"}]},{"type":"paragraph","content":[{"type":"text","text":"The aerospace industry demands exactitude. That''s why our tank services are engineered around key technical and operational benchmarks including ASME, API, DOT, and MIL-STD standards. We support:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Cryogenic liquid tanks (LOX, LH2, LN2, LCH4)"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Hypergolic and chemical fuel tanks"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Water deluge and suppression tanks"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Propellant ground storage and transfer systems"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Custom tank fabrication, modification, and integration"}]}]}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Full-Lifecycle Tank Solutions"}]},{"type":"paragraph","content":[{"type":"text","text":"Services include:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Tank design and fabrication (code-compliant, pressure-rated, custom configuration)"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Inspection and certification (visual, hydrostatic, NDT, compliance documentation)"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Maintenance and refurbishment (valve, liner, joint replacement, insulation rework)"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Integration with support systems (SCADA, fueling, venting, monitoring)"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Emergency repair and retrofit services for in-service assets"}]}]}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Built for Aerospace, Backed by Industry Standards"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Material traceability and full documentation"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Compliance with NASA, DoD, and FAA criteria"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Engineering review and third-party verification when required"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Rigorous quality control and weld inspection"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Integration with facility risk management systems"}]}]}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"The Merickan Way"}]},{"type":"paragraph","content":[{"type":"text","text":"1. Collaborate - We will discover together where we can add value, and what financial impact that will have on your bottom line."}]},{"type":"paragraph","content":[{"type":"text","text":"2. Plan - We will then identify a project that will benefit from our value add, and provide a customized proposal and execution plan."}]},{"type":"paragraph","content":[{"type":"text","text":"3. Execute - After that, we will start delivering results right away, and will leverage EMMS to monitor progress and ensure we focus on continuous improvement."}]}]}'::jsonb, '/images/tank-services.jpg', 5, true),
  ('petrochemical', 'scaffolding-and-access-solutions', 'Petrochemical — Scaffolding & Access Solutions', 'Let us help with your petrochemical scaffolding and access solutions. Solutions tailored for safety, compliance, and productivity at Mericka Group LLC.', '{"type":"doc","content":[{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Scaffolding & Access Solutions for Petrochemical Facilities"}]},{"type":"paragraph","content":[{"type":"text","text":"At Mericka Group, we understand that operating within the petrochemical industry comes with unique challenges and complex access needs. That''s why our Scaffolding & Access Solutions are tailored to meet the high standards required in Texas, Louisiana, and Alaska. With countless successful projects and millions of scaffolding man-hours under our belt, Mericka Group is the trusted name for ensuring safety, efficiency, and reliability in your petrochemical facilities."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Why Scaffolding & Access Solutions Are Essential for Petrochemical Facilities"}]},{"type":"paragraph","content":[{"type":"text","text":"Petrochemical facilities require precision and safety when it comes to elevated work. In states like Texas, Louisiana, and Alaska, where compliance standards and regulations are rigorous, having a partner who excels in scaffolding and access management is non-negotiable."}]},{"type":"paragraph","content":[{"type":"text","text":"Mericka Group sets the standard in creating seamless access to elevated work areas without compromising safety. From data-driven resource management through EMMS (Elevate Management and Monitoring Systems) to employing advanced technology and a skilled labor pool, we make scaffolding simple while adding immense value to your projects."}]},{"type":"paragraph","content":[{"type":"text","text":"What sets our scaffolding solutions apart:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Comprehensive Services: We handle scaffolding, elevated work platforms, stair towers, and rope access solutions to meet your site-specific needs."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Safety-First Approach: Our strategies and procedures prioritize minimizing risks and maintaining impeccable safety records, even at the most challenging heights."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Improved Efficiency: Using innovative tracking systems, we ensure accountability, reduce congestion, and eliminate schedule delays."}]}]}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"How Mericka Group Elevates Petrochemical Projects"}]},{"type":"paragraph","content":[{"type":"text","text":"Our Process:"}]},{"type":"paragraph","content":[{"type":"text","text":"1. Collaborate: We work with you to identify where we can provide value and how our expertise impacts your bottom line."}]},{"type":"paragraph","content":[{"type":"text","text":"2. Plan: Through customized proposals and execution plans, we ensure every step aligns with your project goals."}]},{"type":"paragraph","content":[{"type":"text","text":"3. Execute: Once plans are in place, we deliver immediate results, leveraging EMMS to monitor progress and prioritize continuous improvement."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"The Merickan Way"}]},{"type":"paragraph","content":[{"type":"text","text":"1. Collaborate - We will discover together where we can add value, and what financial impact that will have on your bottom line."}]},{"type":"paragraph","content":[{"type":"text","text":"2. Plan - We will then identify a project that will benefit from our value add, and provide a customized proposal and execution plan."}]},{"type":"paragraph","content":[{"type":"text","text":"3. Execute - After that, we will start delivering results right away, and will leverage EMMS to monitor progress and ensure we focus on continuous improvement."}]}]}'::jsonb, '/images/scaffolding.jpg', 1, true),
  ('petrochemical', 'turnaround-and-outage-support', 'Petrochemical — Turnaround & Outage Support', 'We provided petrochemical turnaround and outage support, ensuring efficient shutdowns and rapid restart. Contact Mericka Group LLC to learn more.', '{"type":"doc","content":[{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Petrochemical Turnaround and Outage Support Services at Mericka Group LLC"}]},{"type":"paragraph","content":[{"type":"text","text":"In the petrochemical world, time is money and downtime is risk. That''s why at Mericka Group LLC, we provide precision-planned turnaround and outage support services for petrochemical facilities operating under tight timelines, strict safety mandates, and performance-critical expectations. Whether you''re preparing for a scheduled maintenance event or recovering from an unplanned outage, we help clients get back online safely, efficiently, and with minimal disruption to operations."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Trusted Turnaround Support for the Gulf Coast Petrochemical Industry"}]},{"type":"paragraph","content":[{"type":"text","text":"At Mericka Group LLC, we specialize in supporting the needs of high-volume, high-risk environments, including ethylene plants, refineries, gas processing units, and downstream chemical facilities. Our support services are tailored for:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Planned shutdowns and annual turnarounds"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Unplanned outages and emergency response"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Plant infrastructure inspection and reinforcement"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Construction, staging, and modular deployment during downtime"}]}]}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Full-Scope Petrochemical Outage Services"}]},{"type":"paragraph","content":[{"type":"text","text":"We don''t just provide labor or rental equipment—we provide full-service outage lifecycle support, integrated with your in-house operations and project controls teams. Our capabilities include:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Pre-turnaround planning (scoping, logistics, site prep)"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Temporary infrastructure installation (scaffolding, shelters, modular structures)"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Civil and mechanical support for shutdown-related construction"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Rapid mobilization and demobilization"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Post-turnaround restoration (cleanup, removal, site grading)"}]}]}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Why Petrochemical Clients Trust Mericka Group LLC"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Fast, safe, and scalable response"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Deep experience in high-compliance industrial environments"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"24/7 availability during critical-path shutdowns"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Proven performance in tight-window turnarounds"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Local knowledge + national delivery capability"}]}]}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Safety-Driven. Schedule-Committed. Built for the Real World."}]},{"type":"paragraph","content":[{"type":"text","text":"Petrochemical turnarounds are about more than tools and timelines—they''re about people, process, and preparedness. At Mericka Group LLC, our teams undergo ongoing training in site-specific compliance, confined space protocols, and emergency readiness."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"The Merickan Way"}]},{"type":"paragraph","content":[{"type":"text","text":"1. Collaborate - We will discover together where we can add value, and what financial impact that will have on your bottom line."}]},{"type":"paragraph","content":[{"type":"text","text":"2. Plan - We will then identify a project that will benefit from our value add, and provide a customized proposal and execution plan."}]},{"type":"paragraph","content":[{"type":"text","text":"3. Execute - After that, we will start delivering results right away, and will leverage EMMS to monitor progress and ensure we focus on continuous improvement."}]}]}'::jsonb, '/images/product-page-scaffolding-and-turnaround.jpg', 2, true),
  ('petrochemical', 'nested-facility-maintenance-programs', 'Petrochemical — Nested Facility Maintenance', 'Mericka Group LLC delivers nested facility maintenance programs to petrochemical plants, maximizing safety and operational continuity.', '{"type":"doc","content":[{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Petrochemical Nested Facility Maintenance Program"}]},{"type":"paragraph","content":[{"type":"text","text":"Operating a petrochemical facility requires more than technical know-how—it takes a reliable, long-term maintenance strategy that minimizes downtime and ensures regulatory compliance. That''s where Mericka Group LLC comes in. We offer a full-scale Petrochemical Nested Facility Maintenance Program tailored to meet the demands of complex facilities facing operational challenges."}]},{"type":"paragraph","content":[{"type":"text","text":"From shutdown support to preventive maintenance and asset integrity management, we embed dedicated teams right into your operation. Our localized approach ensures faster response times, less disruption, and higher plant efficiency."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Why Petrochemical Facilities Need Nested Maintenance Solutions"}]},{"type":"paragraph","content":[{"type":"text","text":"In an environment as demanding as a petrochemical plant, unexpected breakdowns are more than just a nuisance—they''re costly and potentially dangerous. With supply chain delays, weather challenges, and workforce limitations affecting local operations, the need for predictable petrochemical maintenance services has never been greater."}]},{"type":"paragraph","content":[{"type":"text","text":"Mericka Group LLC offers a tailored, long-term solution: our Nested Facility Maintenance Program provides stability, compliance assurance, and 24/7 operational readiness. We staff skilled tradespeople on-site to handle everything from instrumentation calibration to mechanical systems upkeep, helping local operators meet production targets with fewer interruptions."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Comprehensive Petrochemical Maintenance Support from Mericka Group LLC"}]},{"type":"paragraph","content":[{"type":"text","text":"Clients across the area trust Mericka Group LLC to deliver proactive, embedded maintenance services. Our nested maintenance program for petrochemical facilities is designed for seamless integration with your daily operations."}]},{"type":"paragraph","content":[{"type":"text","text":"We provide a full scope of support including mechanical maintenance, rotating equipment services, piping repairs, and electrical system inspections. This local presence means we''re not flying in help—we''re already there. Our technicians become part of your team, familiar with your plant''s systems, schedules, and safety requirements."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Local Petrochemical Facility Maintenance Services Designed for Your Needs"}]},{"type":"paragraph","content":[{"type":"text","text":"We understand the local industry environment. That''s why our petrochemical maintenance services are tailored specifically for your region—not just copied from a national playbook."}]},{"type":"paragraph","content":[{"type":"text","text":"Our teams are embedded in local workforce development programs and have strong ties to safety councils. We''re not just a vendor—we''re part of the industrial fabric, providing steady support to your operations with unmatched consistency and accountability."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Scalable, On-Site Petrochemical Maintenance Programs"}]},{"type":"paragraph","content":[{"type":"text","text":"What sets Mericka Group LLC apart is our ability to scale and adapt. Our on-site petrochemical maintenance programs are flexible enough to support day-to-day reliability and large-scale turnarounds. As your facility grows or adapts to new challenges, so do we."}]},{"type":"paragraph","content":[{"type":"text","text":"Whether your plant needs 10 or 100 skilled professionals, our nested model provides exactly what you need—no more, no less. We monitor KPIs, improve asset reliability, and ensure OSHA and EPA compliance without disruption to your process."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"The Merickan Way"}]},{"type":"paragraph","content":[{"type":"text","text":"1. Collaborate - We will discover together where we can add value, and what financial impact that will have on your bottom line."}]},{"type":"paragraph","content":[{"type":"text","text":"2. Plan - We will then identify a project that will benefit from our value add, and provide a customized proposal and execution plan."}]},{"type":"paragraph","content":[{"type":"text","text":"3. Execute - After that, we will start delivering results right away, and will leverage EMMS to monitor progress and ensure we focus on continuous improvement."}]}]}'::jsonb, '/images/Nested-Maintenance-Background-Picture.jpg', 3, true),
  ('petrochemical', 'subcontracting-partnerships', 'Petrochemical — Subcontracting Partnerships', 'Mericka Group LLC offers subcontracting partnerships for Petrochemical facilities in Texas, Louisiana and Alaska.', '{"type":"doc","content":[{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Offering Subcontracting Partnerships in the Petrochemical Industry"}]},{"type":"paragraph","content":[{"type":"text","text":"At Mericka Group, we specialize in subcontracting partnerships in the petrochemical industry, delivering exceptional support to projects across Texas, Louisiana, and Alaska. Leveraging decades of experience, our award-winning safety culture, and proprietary Enterprise Management & Metrics System (EMMS), we ensure on-schedule project completion, unparalleled cost discipline, and consistent quality throughout every stage of production."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Subcontracting Partnerships Designed for Excellence"}]},{"type":"paragraph","content":[{"type":"text","text":"Our subcontracting services cater to the unique demands of the petrochemical industry, providing unmatched quality and efficiency. At the heart of our operations lies \"The Merickan Way,\" our partnership-focused management style. Through close collaboration, we identify opportunities to add value and develop execution plans tailored to your project''s specific needs."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Why Partner with Mericka Group?"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"On-Schedule Project Completion: We understand the importance of hitting deadlines, and our structured approach supports your project timeline every step of the way."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Cost-Disciplined Approach: Say goodbye to budget overruns with our carefully managed processes that eliminate unnecessary expenses."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Reliable, Data-Driven Insights: Our proprietary EMMS offers robust planning, tracking, and reporting to keep you informed and in control."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Multi-Skilled Labor Pool: With comprehensive expertise across trades, our team ensures premium quality and productivity on every work front."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Award-Winning Safety Culture: Safety is at the core of every project we take on, making us a trusted choice in Texas, Louisiana, and Alaska."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Broad Sector Expertise: With extensive experience in midstream & downstream oil & gas, petrochemical, aerospace, and semiconductor industries."}]}]}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Serving the Petrochemical Industry in Texas, Louisiana & Alaska"}]},{"type":"paragraph","content":[{"type":"text","text":"Mericka Group proudly serves a wide range of clients in Texas, Louisiana, and Alaska, offering expert subcontracting partnerships in the petrochemical industry. Whether you''re located along the Gulf Coast, dealing with high-stakes refinery projects in Louisiana, or operating within Alaska''s stringent industrial environments, our solutions are tailored to overcome the region-specific challenges you face."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"The Merickan Way"}]},{"type":"paragraph","content":[{"type":"text","text":"1. Collaborate - We will discover together where we can add value, and what financial impact that will have on your bottom line."}]},{"type":"paragraph","content":[{"type":"text","text":"2. Plan - We will then identify a project that will benefit from our value add, and provide a customized proposal and execution plan."}]},{"type":"paragraph","content":[{"type":"text","text":"3. Execute - After that, we will start delivering results right away, and will leverage EMMS to monitor progress and ensure we focus on continuous improvement."}]}]}'::jsonb, '/images/scaffold-background-2.jpg', 4, true),
  ('petrochemical', 'comprehensive-storage-tank-services', 'Petrochemical — Comprehensive Storage Tank Services', 'We offer fully comprehensive tank services and solutions to petrochemical companies. Hire Mericka Group LLC as a trusted partner.', '{"type":"doc","content":[{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Comprehensive Tank Services for Petrochemical Companies"}]},{"type":"paragraph","content":[{"type":"text","text":"At Mericka Group, we specialize in delivering comprehensive tank services tailored specifically for petrochemical companies in Texas, Louisiana, and Alaska. As trusted contractors in the industry, we provide a complete range of solutions to ensure the safe, efficient, and compliant operation of your storage tanks, supporting your business''s operational excellence."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Why Choose Mericka Group for Comprehensive Tank Services?"}]},{"type":"paragraph","content":[{"type":"text","text":"Petrochemical companies require an expert partner that understands the complexities of the industry. Storage tanks in this sector store critical liquids, gases, and chemicals, demanding top-tier maintenance and compliance to ensure safety and functionality. Here is what sets Mericka Group apart:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Comprehensive Solutions: We offer a full spectrum of tank services, handling everything from inspection and maintenance to repairs and replacements. No matter your tank-related need, we''ve got you covered."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Industry-Specific Expertise: With years of experience serving petrochemical companies in Texas, Louisiana, and Alaska, we know the unique challenges of your operations and are equipped to provide solutions that work."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Safety and Compliance: Our team is committed to adhering to the highest safety standards, ensuring your tanks meet all regulatory requirements."}]}]}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Services Tailored to Petrochemical Companies in Texas, Louisiana, and Alaska"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Tank Inspections and Assessments: Thorough evaluations to ensure all tanks meet operational and safety standards."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Maintenance Services: Preventative and routine maintenance to extend the lifespan of your tanks."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Repair and Retrofit Solutions: Efficient solutions for tank repairs, ensuring minimized downtime and optimal performance."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"New Installations: Expert installation services for new tanks, ensuring precision and compliance from the start."}]}]}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Benefits for Petrochemical Companies"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Maximize the functionality and efficiency of your storage tanks."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Minimize operational downtime with swift, effective service delivery."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Maintain compliance with all state and federal regulations."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Protect your investment by extending the longevity of your equipment."}]}]}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"The Merickan Way"}]},{"type":"paragraph","content":[{"type":"text","text":"1. Collaborate - We will discover together where we can add value, and what financial impact that will have on your bottom line."}]},{"type":"paragraph","content":[{"type":"text","text":"2. Plan - We will then identify a project that will benefit from our value add, and provide a customized proposal and execution plan."}]},{"type":"paragraph","content":[{"type":"text","text":"3. Execute - After that, we will start delivering results right away, and will leverage EMMS to monitor progress and ensure we focus on continuous improvement."}]}]}'::jsonb, '/images/tank-services.jpg', 5, true),
  ('semiconductor', 'scaffolding-and-access-solutions', 'Semiconductor — Scaffolding & Access Solutions', 'Mericka Group LLC provides cleanroom-compliant scaffolding and access solutions tailored to semiconductor manufacturing facilities. Precision. Safety. Uptime.', '{"type":"doc","content":[{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Semiconductor-Ready Scaffolding & Access Solutions"}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Safe, Precise Access in High-Sensitivity Environments"}]},{"type":"paragraph","content":[{"type":"text","text":"At Mericka Group LLC, we understand the critical nature of cleanliness, access control, and uptime in semiconductor manufacturing. Our Scaffolding and Access Solutions are purpose-built for cleanroom operations, sub-fab systems, and wafer production environments. Whether you''re planning an expansion, performing equipment maintenance, or upgrading high-bay utilities, our systems ensure safe, compliant, and efficient access without disrupting operations."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Engineered for the Semiconductor Sector"}]},{"type":"paragraph","content":[{"type":"text","text":"Cleanroom-Compliant Scaffolding: Our aluminum and composite scaffolding systems are engineered to meet ISO 14644 cleanroom standards, with low-particulate surfaces and non-shedding materials. All equipment is sterilized, and installation crews are trained in gowning, HEPA-safe procedures, and contamination mitigation."}]},{"type":"paragraph","content":[{"type":"text","text":"Precision Installation and Rapid Deployment: We specialize in:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Vertical access to MEP and HVAC systems"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Elevated platforms for tool installation and inspections"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Suspended access systems for sub-fab spaces"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Stair towers and mobile platforms for confined or tight areas"}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"Safety-First Design & Execution: All scaffolding installations adhere to OSHA standards and semiconductor facility safety protocols:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Anti-static and non-conductive material options"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Load-rated platforms for heavy tools or equipment"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Integrated fall protection and guardrail systems"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Detailed work plans with hazard mitigation for every install"}]}]}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Why Semiconductor Leaders Choose Mericka Group LLC"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Contamination Control Built In: Our systems are tailored for environments where microcontamination is mission-critical."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Flexibility for Complex Fab Layouts: Our modular systems can be configured to fit tight spaces, multi-level access points, or intricate architectural constraints."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Improved Uptime and Workflow Continuity: Our turnkey scaffolding solutions are designed to minimize disruptions and keep operations running."}]}]}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"The Merickan Way"}]},{"type":"paragraph","content":[{"type":"text","text":"1. Collaborate - We will discover together where we can add value, and what financial impact that will have on your bottom line."}]},{"type":"paragraph","content":[{"type":"text","text":"2. Plan - We will then identify a project that will benefit from our value add, and provide a customized proposal and execution plan."}]},{"type":"paragraph","content":[{"type":"text","text":"3. Execute - After that, we will start delivering results right away, and will leverage EMMS to monitor progress and ensure we focus on continuous improvement."}]}]}'::jsonb, '/images/scaffolding.jpg', 1, true),
  ('semiconductor', 'turnaround-and-outage-support', 'Semiconductor — Turnaround & Outage Support', 'Mericka Group LLC is an industry trusted partner in solving turnaround and outage issues for the semiconductor industry.', '{"type":"doc","content":[{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Turnaround and Outage Support for Semiconductor Manufacturers"}]},{"type":"paragraph","content":[{"type":"text","text":"At Mericka Group, we provide specialized Turnaround and Outage Support services for semiconductor manufacturers across Texas, Louisiana, and Alaska. With deep industry knowledge and a strong commitment to precision and reliability, we understand the critical demands of semiconductor operations. Our mission is to reduce downtime, maintain cleanroom integrity, and streamline equipment maintenance and upgrades."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"What is Turnaround and Outage Support in the Semiconductor Industry?"}]},{"type":"paragraph","content":[{"type":"text","text":"In the high-stakes world of semiconductor fabrication, even minimal downtime can impact production timelines and profitability. Turnaround and outage support involves the strategic planning and execution of maintenance, upgrades, and repairs—whether during scheduled shutdowns or unplanned outages."}]},{"type":"paragraph","content":[{"type":"text","text":"Key features of our turnaround and outage support include:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Precision Maintenance & Equipment Support: From wafer processing tools to facility infrastructure systems, we provide expert maintenance and upgrades tailored to the semiconductor environment."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Downtime Optimization: We prioritize efficient turnaround times while maintaining strict process control to protect yield and product quality."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Cleanroom Safety & Compliance: Our teams follow stringent protocols to preserve contamination control standards and meet all industry safety and compliance requirements."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Smart Technology Integration: We utilize predictive maintenance tools, analytics, and digital workflow systems to maximize equipment uptime and efficiency."}]}]}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Why Semiconductor Companies Choose Mericka Group"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Deep Regional Experience: We support facilities in key regions like Texas, Louisiana, and Alaska—understanding local infrastructure, environmental challenges, and regulatory landscapes."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Integrated Project Management: From subfab systems to process-critical equipment, we handle multi-discipline scopes under one roof."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Responsive, Predictable Outcomes: Our teams are trained for rapid mobilization, helping semiconductor fabs recover from outages quickly."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Uncompromising Quality and Safety: We work under cleanroom protocols and semiconductor-grade standards to protect your environment, your processes, and your product integrity."}]}]}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"The Merickan Way"}]},{"type":"paragraph","content":[{"type":"text","text":"1. Collaborate - We will discover together where we can add value, and what financial impact that will have on your bottom line."}]},{"type":"paragraph","content":[{"type":"text","text":"2. Plan - We will then identify a project that will benefit from our value add, and provide a customized proposal and execution plan."}]},{"type":"paragraph","content":[{"type":"text","text":"3. Execute - After that, we will start delivering results right away, and will leverage EMMS to monitor progress and ensure we focus on continuous improvement."}]}]}'::jsonb, '/images/product-page-scaffolding-and-turnaround.jpg', 2, true),
  ('semiconductor', 'nested-facility-maintenance-programs', 'Semiconductor — Nested Facility Maintenance', 'Mericka Group LLC delivers high-precision nested facility maintenance programs for semiconductor manufacturers—boosting uptime, compliance, and contamination control.', '{"type":"doc","content":[{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Key Aspects of Nested Facility Maintenance for Semiconductor Manufacturing"}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Precision Maintenance for Precision Manufacturing"}]},{"type":"paragraph","content":[{"type":"text","text":"Mericka Group LLC helps semiconductor manufacturers streamline operations, reduce contamination risks, and extend equipment life through specialized Nested Facility Maintenance Programs (NFMP). Designed for fab environments, R&D labs, and wafer production lines, our program consolidates soft-craft services—cleanroom-compliant scaffolding, chemical-resistant insulation, specialized coatings, and lead/asbestos abatement—under one expert provider."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"A Hierarchical Framework Built for the Fab"}]},{"type":"paragraph","content":[{"type":"text","text":"In semiconductor environments where uptime is everything, a layered maintenance strategy is essential. Our NFMP establishes a structured hierarchy tailored to each unit''s function and criticality—whether it''s lithography tools, sub-fab utility systems, HVAC/air filtration systems, or process gas distribution lines."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Risk-Based Prioritization for Contamination and Downtime Prevention"}]},{"type":"paragraph","content":[{"type":"text","text":"Our system prioritizes maintenance tasks using risk factors specific to semiconductor manufacturing:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Contamination control for cleanrooms (ISO 14644 compliance)"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Safety hazards associated with high-voltage systems or toxic gas leaks"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Operational impact (impact to line yield, throughput, or wafer defect rates)"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Regulatory mandates and audit readiness (OSHA, EPA, industry certifications)"}]}]}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Integrated Scheduling for Zero Tolerance Downtime"}]},{"type":"paragraph","content":[{"type":"text","text":"Semiconductor fabs operate with razor-thin margins for disruption. NFMP aligns maintenance activities across critical sub-systems—like chilled water, vacuum lines, and process gases—to minimize production interruptions. Our resource planning engine coordinates personnel, PPE requirements, and specialized tools to ensure cleanroom protocols are strictly followed."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Predictive Maintenance Through Real-Time Data"}]},{"type":"paragraph","content":[{"type":"text","text":"NFMP incorporates IoT sensors, condition monitoring, and failure history to forecast maintenance needs. For example, pressure drops in gas delivery lines or changes in humidity within cleanrooms can signal the need for preemptive intervention."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Why Semiconductor Facilities Rely on Nested Maintenance"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Continuous Yield with Fewer Disruptions: Our NFMP enables predictive, priority-based interventions that keep production moving while safeguarding yield."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Cost Savings Through Smarter Maintenance: By timing maintenance activities based on real-world conditions and criticality, NFMP reduces unnecessary service and emergency fixes."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Cleanroom Compliance and Safety: All procedures are documented for traceability, ensuring readiness for customer audits or regulatory inspections."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Scalable and Adaptable to New Tech: NFMP''s modular design makes integration fast and disruption minimal."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Protecting Your Capital Investments: NFMP protects high-value assets with predictive servicing and cleanroom-grade intervention protocols."}]}]}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"The Merickan Way"}]},{"type":"paragraph","content":[{"type":"text","text":"1. Collaborate - We will discover together where we can add value, and what financial impact that will have on your bottom line."}]},{"type":"paragraph","content":[{"type":"text","text":"2. Plan - We will then identify a project that will benefit from our value add, and provide a customized proposal and execution plan."}]},{"type":"paragraph","content":[{"type":"text","text":"3. Execute - After that, we will start delivering results right away, and will leverage EMMS to monitor progress and ensure we focus on continuous improvement."}]}]}'::jsonb, '/images/Nested-Maintenance-Background-Picture.jpg', 3, true),
  ('semiconductor', 'subcontracting-partnerships', 'Semiconductor — Subcontracting Partnerships', 'We provide subcontracting partnerships to semiconductor facilities. How can Mericka Group LLC support your business? Give us a call to learn more.', '{"type":"doc","content":[{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Subcontracting Partnerships with Semiconductor Manufacturing Facilities"}]},{"type":"paragraph","content":[{"type":"text","text":"At Mericka Group, we specialize in delivering reliable subcontracting partnerships tailored specifically for semiconductor companies. With a commitment to excellence, we offer innovative solutions, consistent execution, and precise project reporting, making us the ideal partner for businesses in the semiconductor manufacturing industry."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Why Choose Subcontracting Partnerships with Mericka Group?"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Consistent Execution for Superior Results: We understand the critical nature of semiconductor manufacturing projects. By leveraging well-trained subcontractors, we ensure your clients receive the quality and reliability needed to maintain high standards."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Accurate Project Reporting: Mericka Group excels in providing accurate, detailed project reporting, allowing you to manage your projects effectively. With transparency at every stage, you can stay informed and make better decisions."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Innovative Solutions to Stay Competitive: Our team is dedicated to delivering innovative solutions that set you apart in the competitive semiconductor manufacturing industry."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Eliminate Cost Disputes with Proper Planning: We prioritize meticulous estimating and planning, ensuring every aspect of your project is accounted for. This reduces the risk of unforeseen expenses and eliminates cost disputes."}]}]}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Who Can Benefit from This Partnership?"}]},{"type":"paragraph","content":[{"type":"text","text":"Whether you are a large-scale semiconductor manufacturing firm or a growing company looking to improve operational efficiency, Mericka Group provides subcontracting services customized to your needs. With extensive knowledge of the semiconductor sector, we understand the unique challenges you face."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"The Merickan Way"}]},{"type":"paragraph","content":[{"type":"text","text":"1. Collaborate - We will discover together where we can add value, and what financial impact that will have on your bottom line."}]},{"type":"paragraph","content":[{"type":"text","text":"2. Plan - We will then identify a project that will benefit from our value add, and provide a customized proposal and execution plan."}]},{"type":"paragraph","content":[{"type":"text","text":"3. Execute - After that, we will start delivering results right away, and will leverage EMMS to monitor progress and ensure we focus on continuous improvement."}]}]}'::jsonb, '/images/scaffold-background-2.jpg', 4, true),
  ('semiconductor', 'comprehensive-storage-tank-services', 'Semiconductor — Comprehensive Storage Tank Services', 'Partner with Mericka Group LLC for comprehensive tank services for semiconductor manufacturing facilities.', '{"type":"doc","content":[{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Comprehensive Tank Services in Semiconductor Manufacturing Facilities"}]},{"type":"paragraph","content":[{"type":"text","text":"At Mericka Group, we specialize in providing comprehensive tank services tailored to meet the precise needs of semiconductor manufacturing facilities. Semiconductor manufacturing demands rigorous control of fluids like ultrapure water, chemicals, and gases, making high-performance tanks a cornerstone of the industry."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"What Are Comprehensive Tank Services?"}]},{"type":"paragraph","content":[{"type":"text","text":"Comprehensive tank services encompass the full lifecycle of tank management required in semiconductor manufacturing facilities. This includes installation, maintenance, inspection, repair, and compliance testing of specialized tanks used for storing and processing sensitive materials."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Why Semiconductor Manufacturing Facilities Need Our Expertise"}]},{"type":"paragraph","content":[{"type":"text","text":"1. Ultrapure Water Storage - Semiconductors require water in its purest form for wafer cleaning, rinsing, and other processes. Mericka Group ensures optimal storage conditions to maintain water purity, free from contamination."}]},{"type":"paragraph","content":[{"type":"text","text":"2. Chemical and Gas Management - Tanks dealing with chemicals and gases for etching, doping, or material deposition need to handle aggressive and sensitive materials safely."}]},{"type":"paragraph","content":[{"type":"text","text":"3. Custom Solutions for Efficiency - Each semiconductor facility has unique requirements. We work closely with our clients to design, install, and maintain tanks tailored to their specific operational needs."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Why Choose Mericka Group for Comprehensive Tank Services?"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Industry Expertise: Decades of experience serving the specific needs of semiconductor manufacturing facilities."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"End-to-End Services: From installation to maintenance, our offerings cover the entire lifecycle of your tank systems."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Custom Solutions: Tailored services to ensure your facility runs efficiently while meeting industry standards."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Compliance and Safety Assurance: We ensure all tanks meet the necessary regulations, safeguarding your operations and employees."}]}]}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"The Merickan Way"}]},{"type":"paragraph","content":[{"type":"text","text":"1. Collaborate - We will discover together where we can add value, and what financial impact that will have on your bottom line."}]},{"type":"paragraph","content":[{"type":"text","text":"2. Plan - We will then identify a project that will benefit from our value add, and provide a customized proposal and execution plan."}]},{"type":"paragraph","content":[{"type":"text","text":"3. Execute - After that, we will start delivering results right away, and will leverage EMMS to monitor progress and ensure we focus on continuous improvement."}]}]}'::jsonb, '/images/tank-services.jpg', 5, true),
  ('downstream-oil-gas', 'scaffolding-and-access-solutions', 'Downstream Oil & Gas — Scaffolding & Access Solutions', 'Mericka Group LLC delivers top-notch scaffolding and access solutions for downstream oil & gas to enhance safety and productivity at every level.', '{"type":"doc","content":[{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Scaffolding and Access Solutions for the Downstream Oil and Gas Market"}]},{"type":"paragraph","content":[{"type":"text","text":"When it comes to the downstream oil and gas industry, safety, efficiency, and precision aren''t just important—they''re essential. Our scaffolding and access solutions are designed to keep your operations running smoothly and your crews safe while meeting compliance and budget needs."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"How Mericka Group LLC Supports Your Business"}]},{"type":"paragraph","content":[{"type":"text","text":"We''ve partnered with numerous facilities delivering custom scaffolding and access strategies that meet specific site demands. We build access systems that adapt to your project scope and constraints."}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Trusted Scaffolding Services for the Downstream Oil and Gas Sector"}]},{"type":"paragraph","content":[{"type":"text","text":"From fixed pipe rack systems to suspended scaffolding for difficult-to-reach areas, we tailor our solutions to ensure minimal disruption and maximum safety. From turnaround schedules to audit preparation, Mericka Group has the scaffolding systems that keep your project moving forward."}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"The Importance of Safe and Reliable Access Solutions"}]},{"type":"paragraph","content":[{"type":"text","text":"We offer modular, adjustable access systems designed to accommodate evolving conditions and complex layouts common in downstream facilities. Our teams help reduce downtime and keep compliance at the forefront of every setup."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Why Scaffolding and Access Solutions Are Essential"}]},{"type":"paragraph","content":[{"type":"text","text":"Without dependable scaffolding and access support, the risk of delays and accidents grows. We help you stay on schedule, stay compliant, and stay safe."}]}]}'::jsonb, '/images/scaffolding.jpg', 1, true),
  ('downstream-oil-gas', 'turnaround-and-outage-support', 'Downstream Oil & Gas — Turnaround & Outage Support', 'Mericka Group provides expert turnaround and outage support for downstream oil and gas operations in Texas, Louisiana, and Alaska, minimizing disruptions and maximizing efficiency.', '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"Mericka Group delivers comprehensive turnaround and outage support for downstream oil and gas facilities across Texas, Louisiana, and Alaska. Our experienced teams are equipped to handle the most complex turnaround projects, ensuring your facility returns to full operation as quickly and safely as possible."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Minimized Disruptions"}]},{"type":"paragraph","content":[{"type":"text","text":"We understand that every hour of downtime represents lost revenue. Our teams work efficiently and safely to minimize the duration of your turnaround or outage, getting your facility back online as quickly as possible."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Cost Efficiency"}]},{"type":"paragraph","content":[{"type":"text","text":"Our experienced project managers and skilled craft workers help control costs throughout the turnaround process. We provide accurate cost estimates upfront and work diligently to stay within budget."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Safety Focus"}]},{"type":"paragraph","content":[{"type":"text","text":"Safety is our top priority on every project. We implement rigorous safety protocols and conduct thorough training to ensure that every team member understands and adheres to our safety standards."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Service Areas"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Texas"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Louisiana"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Alaska"}]}]}]}]}'::jsonb, '/images/product-page-scaffolding-and-turnaround.jpg', 2, true),
  ('downstream-oil-gas', 'nested-facility-maintenance-programs', 'Downstream Oil & Gas — Nested Facility Maintenance', 'Mericka Group offers nested facility maintenance programs for downstream oil and gas operations, providing risk-based prioritization, integrated scheduling, and data-driven decision making.', '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"Mericka Group''s nested facility maintenance programs are designed to keep your downstream oil and gas operations running at peak efficiency. Our comprehensive approach integrates seamlessly with your existing operations, providing the support you need to maintain reliability and safety."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Risk-Based Prioritization"}]},{"type":"paragraph","content":[{"type":"text","text":"We use advanced risk assessment methodologies to prioritize maintenance tasks based on their potential impact on operations, safety, and compliance. This ensures that critical assets receive attention first, reducing the likelihood of unexpected failures."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Integrated Scheduling"}]},{"type":"paragraph","content":[{"type":"text","text":"Our maintenance programs are designed to integrate with your operational schedules, minimizing disruptions and maximizing uptime. We work closely with your team to develop maintenance windows that align with your production cycles."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Data-Driven Decision Making"}]},{"type":"paragraph","content":[{"type":"text","text":"We leverage real-time data and advanced analytics to inform our maintenance decisions. This approach allows us to identify emerging issues before they become critical, enabling proactive rather than reactive maintenance."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Benefits Over Alternatives"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Enhanced Reliability: Our programs are designed to maximize equipment uptime and operational reliability."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Cost Efficiency: By preventing unplanned downtime, our programs help reduce the overall cost of maintenance."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Safety: Our risk-based approach ensures that safety-critical assets are prioritized, reducing the likelihood of accidents."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Scalability: Our programs can be scaled to meet the needs of operations of any size."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Asset Longevity: By maintaining equipment to the highest standards, we help extend the life of your assets."}]}]}]}]}'::jsonb, '/images/Nested-Maintenance-Background-Picture.jpg', 3, true),
  ('downstream-oil-gas', 'subcontracting-partnerships', 'Downstream Oil & Gas — Subcontracting Partnerships', 'Mericka Group offers subcontracting partnerships for downstream oil and gas companies, providing consistent execution, accurate reporting, and innovative solutions powered by the EMMS system.', '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"Mericka Group is the trusted subcontracting partner for downstream oil and gas companies. We provide the skilled workforce, management expertise, and innovative solutions you need to complete your projects on time and within budget."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Consistent Execution"}]},{"type":"paragraph","content":[{"type":"text","text":"Our teams are trained and experienced in delivering consistent, high-quality results across all aspects of industrial maintenance and construction. We maintain rigorous quality control standards to ensure that every project meets or exceeds your expectations."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Accurate Reporting"}]},{"type":"paragraph","content":[{"type":"text","text":"We provide comprehensive, real-time reporting on all aspects of project progress, safety, and costs. Our transparent reporting ensures that you always have the information you need to make informed decisions."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Innovative Solutions"}]},{"type":"paragraph","content":[{"type":"text","text":"We leverage innovative technologies and methodologies to deliver better results for our clients. Our EMMS (Equipment Maintenance Management System) provides real-time visibility into equipment status and maintenance activities, enabling more efficient and effective maintenance management."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"EMMS System"}]},{"type":"paragraph","content":[{"type":"text","text":"Our proprietary EMMS system provides:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Real-time equipment status monitoring"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Automated maintenance scheduling"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Comprehensive reporting and analytics"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Integration with existing maintenance management systems"}]}]}]}]}'::jsonb, '/images/scaffold-background-2.jpg', 4, true),
  ('downstream-oil-gas', 'comprehensive-storage-tank-services', 'Downstream Oil & Gas — Comprehensive Storage Tank Services', 'Mericka Group LLC Offers Comprehensive Tank Services for Oil and Gas Companies.', '{"type":"doc","content":[{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Tank Services for Downstream Oil and Gas Companies"}]},{"type":"paragraph","content":[{"type":"text","text":"Mericka Group is your trusted partner for comprehensive tank services, tailored specifically for downstream oil and gas companies. We specialize in providing inspection, maintenance, cleaning, and removal services to ensure the integrity and safe operation of your storage facilities."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Why Tank Services Are Crucial for Downstream Oil and Gas Companies"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Ensure Safety: Proper maintenance helps prevent leaks, spills, and other hazards."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Achieve Compliance Standards: Regulatory compliance is non-negotiable. Our services ensure your tanks meet all industry standards and environmental requirements."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Optimize Operational Efficiency: Clean and well-maintained tanks contribute to smoother workflows and reduced downtime."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Minimize Environmental Risks: A proactive approach minimizes risks such as contamination or spillage."}]}]}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"What Sets Mericka Group Apart?"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Expertise and Experience: Years of experience working with downstream operations."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Commitment to Safety: Every project adheres to stringent safety protocols."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Customized Solutions: Tailored to match the unique needs of your facilities."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Timely Service Delivery: Complete projects within stipulated timelines without compromising on quality."}]}]}]}]}'::jsonb, '/images/tank-services.jpg', 5, true)
